// Obyekt metodunda this
const person = {
  name: 'Ali',
  age: 25,
  introduce: function() {
    return 'Salam, mən ' + this.name + ', ' + this.age + ' yaşım var.';
  }
};

console.log(person.introduce()); // Salam, mən Ali, 25 yaşım var.

// Sinifdə this
class Car {
  constructor(brand, model) {
    this.brand = brand;
    this.model = model;
  }
  getInfo() {
    return this.brand + ' ' + this.model;
  }
}

const myCar = new Car('Toyota', 'Corolla');
console.log(myCar.getInfo()); // Toyota Corolla

// Adi funksiyada this
function showThis() {
  console.log(this); // undefined (strict mode) və ya window (non-strict mode)
}

showThis();

// Obyektə bağlı funksiyada this
const obj = {
  name: 'Test',
  show: function() {
    console.log(this.name);
  }
};

obj.show(); // Test

// Səhvə yol açan nümunə
function showName() {
  console.log(this.name); // undefined (strict mode-da) və ya xəta
}

const person = {
  name: 'Veli',
  show: showName
};

showName(); // Səhv: this.name undefined
person.show(); // Veli

// Düzgün yol
const personCorrect = {
  name: 'Veli',
  show: function() {
    console.log(this.name);
  }
};

personCorrect.show(); // Veli

// Adi funksiya ilə
const person = {
  name: 'Aysu',
  age: 22
};

function introduceStatic(obj) {
  return 'Salam, mən ' + obj.name + ', ' + obj.age + ' yaşım var.';
}

console.log(introduceStatic(person)); // Salam, mən Aysu, 22 yaşım var.

// this ilə eyni nəticə
const personDynamic = {
  name: 'Aysu',
  introduce: function() {
    return 'Salam, mən ' + this.name + ', ' + this.age + ' yaşım var.';
  }
};

console.log(personDynamic.introduce()); // Salam, mən Aysu, 22 yaşım var.

