// this açar sözü sınağı
const book = {
  title: 'JavaScript Guide',
  pages: 300,
  getInfo: function() {
    return this.title + ' has ' + this.pages + ' pages.';
  }
};

console.log(book.getInfo()); // JavaScript Guide has 300 pages.

// Sinifdə this
class Student {
  constructor(name, grade) {
    this.name = name;
    this.grade = grade;
  }
  showGrade() {
    return this.name + ' is in grade ' + this.grade;
  }
}

const student = new Student('Ali', 10);
console.log(student.showGrade()); // Ali is in grade 10

// this ilə digər obyekt
const car = {
  brand: 'Honda',
  model: 'Civic',
  describe: function() {
    return this.brand + ' ' + this.model;
  }
};

console.log(car.describe()); // Honda Civic

