// this in an object method
const person = {
  name: 'Ali',
  age: 25,
  introduce: function() {
    return 'Hello, I am ' + this.name + ', ' + this.age + ' years old.';
  }
};

console.log(person.introduce()); // Hello, I am Ali, 25 years old.

// this in a class
class Car {
  constructor(brand, model) {
    this.brand = brand;
    this.model = model;
  }
  getInfo() {
    return this.brand + ' ' + this.model;
  }
}

const myCar = new Car('Toyota', 'Corolla');
console.log(myCar.getInfo()); // Toyota Corolla

// this in a regular function
function showThis() {
  console.log(this); // undefined (strict mode) or window (non-strict mode)
}

showThis();

// this in a function tied to an object
const obj = {
  name: 'Test',
  show: function() {
    console.log(this.name);
  }
};

obj.show(); // Test

// Error-prone example
function showName() {
  console.log(this.name); // undefined (in strict mode) or error
}

const person = {
  name: 'Veli',
  show: showName
};

showName(); // Error: this.name is undefined
person.show(); // Veli

// Correct approach
const personCorrect = {
  name: 'Veli',
  show: function() {
    console.log(this.name);
  }
};

personCorrect.show(); // Veli

// With a regular function
const person = {
  name: 'Aysu',
  age: 22
};

function introduceStatic(obj) {
  return 'Hello, I am ' + obj.name + ', ' + obj.age + ' years old.';
}

console.log(introduceStatic(person)); // Hello, I am Aysu, 22 years old.

// Same result with this
const personDynamic = {
  name: 'Aysu',
  introduce: function() {
    return 'Hello, I am ' + this.name + ', ' + this.age + ' years old.';
  }
};

console.log(personDynamic.introduce()); // Hello, I am Aysu, 22 years old.

